UPDATE guardian_term_templates SET is_active = false WHERE type = 'minor_event' AND is_active = true;

INSERT INTO guardian_term_templates (version, content, is_active, type)
SELECT
    COALESCE((SELECT MAX(version) FROM guardian_term_templates WHERE type = 'minor_event'), 0) + 1,
    E'TERMO DE RESPONSABILIDADE E AUTORIZAÇÃO PARA PARTICIPAÇÃO EM EVENTO ESPORTIVO\n\nEu, {{responsavel_nome}}, portador(a) do CPF {{responsavel_cpf}}, na qualidade de {{responsavel_vinculo}} do(a) atleta {{atleta_nome}}, por este instrumento e na melhor forma de direito, AUTORIZO e DECLARO:\n\n1. AUTORIZAÇÃO DE PARTICIPAÇÃO\nAutorizo o(a) atleta {{atleta_nome}} a participar do evento esportivo "{{evento_nome}}", realizado em {{evento_local}}, na data de {{evento_data}}.\n\n2. CIÊNCIA DOS RISCOS\nDeclaro estar ciente dos riscos inerentes à prática de esportes de contato e asseguro que o(a) atleta está em plenas condições físicas e de saúde para participar da competição.\n\n3. RESPONSABILIDADE\nAsumo total responsabilidade pelo(a) atleta durante o período do evento, comprometendo-me a responder por quaisquer danos ou incidentes que possam ocorrer.\n\n4. REFERÊNCIA AO TERMO DE CADASTRO\nEste termo complementa e está vinculado ao Termo de Responsabilidade assinado no momento do cadastro na plataforma Competir, o qual já formaliza a autorização geral para participação em competições esportivas.\n\n5. VERACIDADE DAS INFORMAÇÕES\nDeclaro que todas as informações prestadas são verdadeiras e assumo responsabilidade pelas informações fornecidas.\n\nAo aceitar eletronicamente este termo, declaro ter lido e compreendido todas as cláusulas acima.\n\n{{responsavel_nome}}\nCPF: {{responsavel_cpf}}\nVínculo: {{responsavel_vinculo}}\nTelefone: {{responsavel_telefone}}\n\nData de aceite: {{data}}',
    true,
    'minor_event';
